import React, { useState, useEffect } from 'react';
import api from '../services/api';

const CrearOferta = () => {
  const [formData, setFormData] = useState({
    programa_formacion: '',
    modalidad: '',
    tipo_programa: '',
    tipo_oferta: '',
    cupo_maximo: '',
    ambiente: {
      nombre: ''
    },
    fechas: {
      inicio: '',
      fin: ''
    },
    ubicacion: {
      departamento: 'Cauca',
      municipio: ''
    },
    empresa_solicitante: {
      nombre: ''
    },
    subsector_economico: {
      nombre: ''
    },
    horario: {
      hora_inicio: '08:00',
      hora_fin: '12:00',
      dias: []
    },
    observaciones: ''
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Estados para las opciones de los selects
  const [programas, setProgramas] = useState([]);
  const [modalidades, setModalidades] = useState([]);
  const [tiposPrograma, setTiposPrograma] = useState([]);
  const [tiposOferta, setTiposOferta] = useState([]);
  const [municipios, setMunicipios] = useState([]);

  // Cargar datos de MongoDB al montar el componente
  useEffect(() => {
    cargarDatosIniciales();
  }, []);

  const cargarDatosIniciales = async () => {
    try {
      const [
        programasRes,
        modalidadesRes,
        tiposProgramaRes,
        tiposOfertaRes,
        municipiosRes
      ] = await Promise.all([
        api.get('/programas-formacion'),
        api.get('/modalidades'),
        api.get('/tipos-programa'),
        api.get('/tipos-oferta'),
        api.get('/municipios')
      ]);

      setProgramas(programasRes.data.data || []);
      setModalidades(modalidadesRes.data.data || []);
      setTiposPrograma(tiposProgramaRes.data.data || []);
      setTiposOferta(tiposOfertaRes.data.data || []);
      setMunicipios(municipiosRes.data.data || []);
    } catch (error) {
      console.error('Error cargando datos:', error);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    
    if (name.includes('.')) {
      const [parent, child] = name.split('.');
      setFormData({
        ...formData,
        [parent]: {
          ...formData[parent],
          [child]: value
        }
      });
    } else {
      setFormData({
        ...formData,
        [name]: value
      });
    }
  };

  const handleDiaChange = (e) => {
    const { value, checked } = e.target;
    if (checked) {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: [...formData.horario.dias, value]
        }
      });
    } else {
      setFormData({
        ...formData,
        horario: {
          ...formData.horario,
          dias: formData.horario.dias.filter(dia => dia !== value)
        }
      });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setSuccess('');

    try {
      if (!formData.programa_formacion) throw new Error('Seleccione un programa de formación');
      if (!formData.modalidad) throw new Error('Seleccione una modalidad');
      if (!formData.tipo_programa) throw new Error('Seleccione un tipo de programa');
      if (!formData.tipo_oferta) throw new Error('Seleccione un tipo de oferta');
      if (!formData.cupo_maximo) throw new Error('Ingrese el cupo máximo');
      if (!formData.ambiente.nombre) throw new Error('Ingrese el nombre del ambiente');
      if (!formData.fechas.inicio || !formData.fechas.fin) throw new Error('Ingrese las fechas');
      if (!formData.ubicacion.municipio) throw new Error('Seleccione un municipio');
      if (!formData.empresa_solicitante.nombre) throw new Error('Ingrese el nombre de la empresa');
      if (!formData.subsector_economico.nombre) throw new Error('Ingrese el subsector económico');
      if (formData.horario.dias.length === 0) throw new Error('Seleccione al menos un día');

      const fechaInicio = new Date(formData.fechas.inicio);
      const fechaFin = new Date(formData.fechas.fin);
      if (fechaFin <= fechaInicio) {
        throw new Error('La fecha de fin debe ser posterior a la fecha de inicio');
      }

      const datosEnvio = {
        ...formData,
        cupo_maximo: parseInt(formData.cupo_maximo)
      };

      console.log('Enviando datos:', datosEnvio);
      
      const response = await api.post('/ofertas', datosEnvio);
      
      setSuccess('✅ Oferta creada exitosamente');
      console.log('Respuesta:', response.data);
      
      setTimeout(() => {
        window.location.reload();
      }, 2000);
      
    } catch (error) {
      console.error('Error:', error);
      if (error.response?.data?.errors) {
        setError(error.response.data.errors.join(', '));
      } else if (error.response?.data?.message) {
        setError(error.response.data.message);
      } else {
        setError(error.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const diasSemana = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

  return (
    <div style={styles.container}>
      <h2 style={styles.title}>➕ Crear Nueva Oferta</h2>
      
      {error && <div style={styles.errorAlert}>❌ {error}</div>}
      {success && <div style={styles.successAlert}>✅ {success}</div>}

      <form onSubmit={handleSubmit} style={styles.form}>
        
        {/* PROGRAMA DE FORMACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Programa de Formación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Programa:</label>
            <select 
              name="programa_formacion"
              value={formData.programa_formacion}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {programas.map(prog => (
                <option key={prog._id} value={prog._id}>
                  {prog.nombre_programa} - {prog.codigo}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Modalidad:</label>
            <select 
              name="modalidad"
              value={formData.modalidad}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {modalidades.map(mod => (
                <option key={mod._id} value={mod._id}>
                  {mod.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Programa:</label>
            <select 
              name="tipo_programa"
              value={formData.tipo_programa}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposPrograma.map(tp => (
                <option key={tp._id} value={tp._id}>
                  {tp.nombre}
                </option>
              ))}
            </select>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Tipo de Oferta:</label>
            <select 
              name="tipo_oferta"
              value={formData.tipo_oferta}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {tiposOferta.map(to => (
                <option key={to._id} value={to._id}>
                  {to.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* CUPOS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Cupos</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Cupo Máximo:</label>
            <input 
              type="number"
              name="cupo_maximo"
              value={formData.cupo_maximo}
              onChange={handleChange}
              style={styles.input}
              placeholder="30"
              min="1"
              required
            />
          </div>
        </div>

        {/* AMBIENTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ambiente</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre del Ambiente:</label>
            <input 
              type="text"
              name="ambiente.nombre"
              value={formData.ambiente.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Aula 101"
              required
            />
          </div>
        </div>

        {/* FECHAS */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Fechas</h3>
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Inicio:</label>
              <input 
                type="date"
                name="fechas.inicio"
                value={formData.fechas.inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Fecha Fin:</label>
              <input 
                type="date"
                name="fechas.fin"
                value={formData.fechas.fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>
        </div>

        {/* UBICACIÓN */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Ubicación</h3>
          
          <div style={styles.formGroup}>
            <label style={styles.label}>Departamento:</label>
            <input 
              type="text"
              name="ubicacion.departamento"
              value={formData.ubicacion.departamento}
              onChange={handleChange}
              style={styles.input}
              placeholder="Cauca"
              required
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Municipio:</label>
            <select 
              name="ubicacion.municipio"
              value={formData.ubicacion.municipio}
              onChange={handleChange}
              style={styles.select}
              required
            >
              <option value="">Seleccione...</option>
              {municipios.map(mun => (
                <option key={mun._id} value={mun._id}>
                  {mun.nombre}
                </option>
              ))}
            </select>
          </div>
        </div>

        {/* EMPRESA SOLICITANTE */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Empresa Solicitante</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre de la Empresa:</label>
            <input 
              type="text"
              name="empresa_solicitante.nombre"
              value={formData.empresa_solicitante.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Nombre de la empresa"
              required
            />
          </div>
        </div>

        {/* SUBSECTOR ECONÓMICO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Subsector Económico</h3>
          <div style={styles.formGroup}>
            <label style={styles.label}>Nombre:</label>
            <input 
              type="text"
              name="subsector_economico.nombre"
              value={formData.subsector_economico.nombre}
              onChange={handleChange}
              style={styles.input}
              placeholder="Ej: Tecnologías de la Información"
              required
            />
          </div>
        </div>

        {/* HORARIO */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Horario</h3>
          
          <div style={styles.row}>
            <div style={styles.half}>
              <label style={styles.label}>Hora Inicio:</label>
              <input 
                type="time"
                name="horario.hora_inicio"
                value={formData.horario.hora_inicio}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
            <div style={styles.half}>
              <label style={styles.label}>Hora Fin:</label>
              <input 
                type="time"
                name="horario.hora_fin"
                value={formData.horario.hora_fin}
                onChange={handleChange}
                style={styles.input}
                required
              />
            </div>
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label}>Días:</label>
            <div style={styles.checkboxGroup}>
              {diasSemana.map(dia => (
                <label key={dia} style={styles.checkboxLabel}>
                  <input 
                    type="checkbox"
                    value={dia}
                    checked={formData.horario.dias.includes(dia)}
                    onChange={handleDiaChange}
                  /> {dia}
                </label>
              ))}
            </div>
          </div>
        </div>

        {/* OBSERVACIONES */}
        <div style={styles.section}>
          <h3 style={styles.sectionTitle}>Observaciones</h3>
          <div style={styles.formGroup}>
            <textarea
              name="observaciones"
              value={formData.observaciones}
              onChange={handleChange}
              style={styles.textarea}
              rows="3"
              placeholder="Observaciones adicionales..."
            />
          </div>
        </div>

        <button 
          type="submit" 
          style={loading ? {...styles.submitButton, ...styles.buttonDisabled} : styles.submitButton}
          disabled={loading}
        >
          {loading ? 'Guardando...' : 'Guardar Oferta'}
        </button>
      </form>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '800px',
    margin: '0 auto',
    padding: '20px'
  },
  title: {
    color: '#2c3e50',
    borderBottom: '3px solid #3498db',
    paddingBottom: '10px',
    marginBottom: '30px',
    fontSize: '28px'
  },
  section: {
    backgroundColor: '#f8f9fa',
    padding: '20px',
